import { extractString } from '../../../../utils/extract.js';
import { handleError } from '../../../error.js';
export const createServerPreUploadItemCommunityCommentActionRouteHandler = (group) => async ({ req, res, next, localize, ctx }) => {
    if (!group.community.comment.preUploadHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const commentName = req.params.commentName;
    if (!commentName) {
        res.status(400).end();
        return;
    }
    const key = extractString(req.headers['sonolus-upload-key']);
    if (key === undefined) {
        res.status(400).end();
        return;
    }
    const response = await group.community.comment.preUploadHandler({
        ...ctx,
        itemName,
        commentName,
        key,
    });
    if (handleError(response, res, localize))
        return;
    next();
};
